// Query the system contacts provider — list all names
val names = mutableListOf<String>()
contentResolver.query(
  ContactsContract.Contacts.CONTENT_URI,
  arrayOf(ContactsContract.Contacts.DISPLAY_NAME),
  null, null, null,
)?.use { cursor ->
  while (cursor.moveToNext()) {
    names += cursor.getString(0)
  }
}
// Requires <uses-permission android:name="android.permission.READ_CONTACTS" />
// AND a runtime-permission request on Android 6+

// Query MediaStore for images captured in the last week
val since = System.currentTimeMillis() / 1000 - 7 * 24 * 3600
contentResolver.query(
  MediaStore.Images.Media.EXTERNAL_CONTENT_URI,
  arrayOf(MediaStore.Images.Media._ID, MediaStore.Images.Media.DISPLAY_NAME),
  "${MediaStore.Images.Media.DATE_ADDED} >= ?",
  arrayOf(since.toString()),
  "${MediaStore.Images.Media.DATE_ADDED} DESC",
)?.use { c ->
  // iterate — result IDs can be composed into content URIs to display or share
}

// Share a file with another app (email, chat, docs) — never expose file:// directly since Android 7
val file = File(cacheDir, "shared/report.pdf")
val uri = FileProvider.getUriForFile(this, "$packageName.fileprovider", file)

val share = Intent(Intent.ACTION_SEND).apply {
  type = "application/pdf"
  putExtra(Intent.EXTRA_STREAM, uri)
  addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)   // grant temporary access to receiver
}
startActivity(Intent.createChooser(share, "Share report"))

